export interface DocumentAnalysis {
  summary: string;
  documentType: string;
  keyEntities: Record<string, string | number | boolean>;
  rawText: string;
}

export interface ChatMessage {
  id: string;
  role: 'user' | 'model';
  text: string;
  timestamp: number;
}

export enum AppState {
  IDLE = 'IDLE',
  ANALYZING = 'ANALYZING',
  VIEWING = 'VIEWING',
  ERROR = 'ERROR'
}

export interface UploadedFile {
  file: File;
  previewUrl: string;
  base64: string;
  mimeType: string;
}

import { GoogleGenAI, Type, Schema } from "@google/genai";
import { DocumentAnalysis } from "../types";

const MODEL_NAME = "gemini-3-flash-preview";

// Helper to get API client
const getClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API Key not found in environment variables");
  }
  return new GoogleGenAI({ apiKey });
};

export const analyzeDocument = async (
  base64Data: string, 
  mimeType: string
): Promise<DocumentAnalysis> => {
  const ai = getClient();

  const analysisSchema: Schema = {
    type: Type.OBJECT,
    properties: {
      summary: { type: Type.STRING, description: "A concise summary of the document content." },
      documentType: { type: Type.STRING, description: "The type of document (e.g., Receipt, Invoice, Contract, Graph, Handwritten Note)." },
      keyEntities: { 
        type: Type.OBJECT, 
        description: "Key extracted data fields as key-value pairs (e.g., total_amount, date, names, percentages). Flat structure preferred.",
        nullable: true
      },
      rawText: { type: Type.STRING, description: "The main textual content extracted from the document." }
    },
    required: ["summary", "documentType", "rawText"]
  };

  try {
    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: {
        parts: [
          {
            inlineData: {
              data: base64Data,
              mimeType: mimeType
            }
          },
          {
            text: "Analyze this document image. Provide a summary, identify the type, extract all relevant key entities into a structured JSON object, and transcribe the main text."
          }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: analysisSchema,
        systemInstruction: "You are DocuLens, an expert document analysis AI. Your goal is to extract accurate information from images.",
        thinkingConfig: { thinkingBudget: 1024 } // allocating a small budget for extraction logic
      }
    });

    const text = response.text;
    if (!text) throw new Error("No response from Gemini");

    return JSON.parse(text) as DocumentAnalysis;
  } catch (error) {
    console.error("Analysis failed:", error);
    throw error;
  }
};

export class DocumentChatSession {
  private chat: any;
  private history: any[] = [];
  private imagePart: any;

  constructor(base64Data: string, mimeType: string) {
    const ai = getClient();
    this.imagePart = {
      inlineData: {
        data: base64Data,
        mimeType: mimeType
      }
    };

    // Initialize chat with the image in context via system instruction or first history turn is tricky in stateless web.
    // We will initialize the chat object.
    this.chat = ai.chats.create({
      model: MODEL_NAME,
      config: {
        systemInstruction: "You are a helpful assistant analyzing a specific document provided by the user. Answer questions based on the document content.",
      }
    });
  }

  async sendMessage(message: string): Promise<string> {
    try {
      // For the very first message, we might want to attach the image if it hasn't been established.
      // However, since we are maintaining a session class, let's just send the image with the first prompt 
      // OR send it every time if the API requires (Gemini 1.5+ has long context window, so once is usually enough).
      // But standard Chat object in SDK manages history. 

      // Strategy: Check if history is empty. If so, send image + text. Else, send text.
      let response;
      if (this.history.length === 0) {
        response = await this.chat.sendMessage({
          message: {
            parts: [
              this.imagePart,
              { text: message }
            ]
          }
        });
      } else {
        response = await this.chat.sendMessage({
          message: {
            parts: [{ text: message }]
          }
        });
      }

      // Update local tracking if needed, but chat object handles it.
      this.history.push({ role: 'user', parts: [{ text: message }] }); // Simplified
      this.history.push({ role: 'model', parts: [{ text: response.text }] });

      return response.text || "I couldn't generate a response.";
    } catch (error) {
      console.error("Chat error:", error);
      throw error;
    }
  }
}

import React, { useCallback, useState } from 'react';
import { Icons } from './ui/Icons';

interface FileUploaderProps {
  onFileSelect: (file: File) => void;
}

export const FileUploader: React.FC<FileUploaderProps> = ({ onFileSelect }) => {
  const [isDragging, setIsDragging] = useState(false);

  const handleDragOver = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(true);
  }, []);

  const handleDragLeave = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
  }, []);

  const handleDrop = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);

    if (e.dataTransfer.files && e.dataTransfer.files.length > 0) {
      const file = e.dataTransfer.files[0];
      if (validateFile(file)) {
        onFileSelect(file);
      }
    }
  }, [onFileSelect]);

  const handleFileInput = useCallback((e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      const file = e.target.files[0];
      if (validateFile(file)) {
        onFileSelect(file);
      }
    }
  }, [onFileSelect]);

  const validateFile = (file: File) => {
    const validTypes = ['image/jpeg', 'image/png', 'image/webp', 'application/pdf']; // PDF requires pdf-to-image usually, limiting to images for this demo
    // For this pure frontend React demo without PDF worker, we limit to Images.
    const validImages = ['image/jpeg', 'image/png', 'image/webp'];

    if (!validImages.includes(file.type)) {
      alert('Currently supporting Image files (JPG, PNG, WEBP) for instant analysis.');
      return false;
    }
    if (file.size > 10 * 1024 * 1024) { // 10MB
      alert('File size too large (Max 10MB).');
      return false;
    }
    return true;
  };

  return (
    <div 
      className={`
        relative group cursor-pointer 
        border-2 border-dashed rounded-xl p-12 
        transition-all duration-300 ease-in-out
        flex flex-col items-center justify-center text-center
        ${isDragging 
          ? 'border-indigo-500 bg-indigo-50/50 scale-[1.02]' 
          : 'border-slate-300 hover:border-indigo-400 hover:bg-slate-50'
        }
      `}
      onDragOver={handleDragOver}
      onDragLeave={handleDragLeave}
      onDrop={handleDrop}
      onClick={() => document.getElementById('fileInput')?.click()}
    >
      <input 
        type="file" 
        id="fileInput" 
        className="hidden" 
        accept="image/png, image/jpeg, image/webp"
        onChange={handleFileInput}
      />

      <div className={`
        p-4 rounded-full mb-4 transition-colors duration-300
        ${isDragging ? 'bg-indigo-100 text-indigo-600' : 'bg-slate-100 text-slate-500 group-hover:bg-indigo-50 group-hover:text-indigo-500'}
      `}>
        <Icons.Upload className="w-8 h-8" />
      </div>

      <h3 className="text-lg font-semibold text-slate-700 mb-1">
        Upload Document
      </h3>
      <p className="text-sm text-slate-500 mb-4">
        Drag & drop or click to browse
      </p>
      <div className="flex gap-2 text-xs text-slate-400 uppercase tracking-wide font-medium">
        <span>JPG</span>
        <span>•</span>
        <span>PNG</span>
        <span>•</span>
        <span>WEBP</span>
      </div>
    </div>
  );
};

