import React, { useState, useEffect, useRef } from 'react';
import { Icons } from './ui/Icons';
import { ChatMessage } from '../types';
import { DocumentChatSession } from '../services/geminiService';

interface ChatInterfaceProps {
  uploadedFile: { base64: string; mimeType: string } | null;
}

export const ChatInterface: React.FC<ChatInterfaceProps> = ({ uploadedFile }) => {
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [session, setSession] = useState<DocumentChatSession | null>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (uploadedFile) {
      // Reset chat when file changes
      setSession(new DocumentChatSession(uploadedFile.base64, uploadedFile.mimeType));
      setMessages([{
        id: 'intro',
        role: 'model',
        text: 'I\'ve analyzed your document. What would you like to know about it?',
        timestamp: Date.now()
      }]);
    }
  }, [uploadedFile]);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() || !session || isLoading) return;

    const userMsg: ChatMessage = {
      id: Date.now().toString(),
      role: 'user',
      text: input,
      timestamp: Date.now()
    };

    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsLoading(true);

    try {
      const responseText = await session.sendMessage(userMsg.text);
      const botMsg: ChatMessage = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: responseText,
        timestamp: Date.now()
      };
      setMessages(prev => [...prev, botMsg]);
    } catch (error) {
      const errorMsg: ChatMessage = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: "Sorry, I encountered an error answering that. Please try again.",
        timestamp: Date.now()
      };
      setMessages(prev => [...prev, errorMsg]);
    } finally {
      setIsLoading(false);
    }
  };

  if (!uploadedFile) {
    return (
      <div className="h-full flex flex-col items-center justify-center text-slate-400 p-8 text-center bg-white rounded-xl border border-slate-200">
        <Icons.Chat className="w-12 h-12 mb-4 opacity-50" />
        <p>Upload a document to start chatting.</p>
      </div>
    );
  }

  return (
    <div className="flex flex-col h-full bg-white rounded-xl border border-slate-200 shadow-sm overflow-hidden">
      <div className="bg-slate-50 border-b border-slate-200 px-4 py-3 flex items-center gap-2">
        <Icons.Chat className="w-4 h-4 text-indigo-600" />
        <h3 className="text-sm font-semibold text-slate-700">Chat with Document</h3>
      </div>

      <div className="flex-1 overflow-y-auto p-4 space-y-4">
        {messages.map((msg) => (
          <div
            key={msg.id}
            className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}
          >
            <div
              className={`max-w-[85%] rounded-2xl px-4 py-3 text-sm leading-relaxed ${
                msg.role === 'user'
                  ? 'bg-indigo-600 text-white rounded-tr-sm shadow-md shadow-indigo-100'
                  : 'bg-slate-100 text-slate-800 rounded-tl-sm border border-slate-200'
              }`}
            >
              {msg.text}
            </div>
          </div>
        ))}
        {isLoading && (
          <div className="flex justify-start">
            <div className="bg-slate-100 rounded-2xl rounded-tl-sm px-4 py-3 border border-slate-200 flex items-center gap-2">
               <Icons.Spinner className="w-4 h-4 text-indigo-600 animate-spin" />
               <span className="text-xs text-slate-500">Thinking...</span>
            </div>
          </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      <form onSubmit={handleSubmit} className="p-4 bg-white border-t border-slate-200">
        <div className="relative flex items-center">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            placeholder="Ask a question..."
            className="w-full pl-4 pr-12 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-indigo-500/20 focus:border-indigo-500 transition-all text-sm"
            disabled={isLoading}
          />
          <button
            type="submit"
            disabled={!input.trim() || isLoading}
            className="absolute right-2 p-1.5 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
          >
            <Icons.Send className="w-4 h-4" />
          </button>
        </div>
      </form>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { FileUploader } from './components/FileUploader';
import { AnalysisResult } from './components/AnalysisResult';
import { ChatInterface } from './components/ChatInterface';
import { Icons } from './components/ui/Icons';
import { AppState, DocumentAnalysis, UploadedFile } from './types';
import { analyzeDocument } from './services/geminiService';

const App: React.FC = () => {
  const [state, setState] = useState<AppState>(AppState.IDLE);
  const [uploadedFile, setUploadedFile] = useState<UploadedFile | null>(null);
  const [analysis, setAnalysis] = useState<DocumentAnalysis | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [showFullImage, setShowFullImage] = useState(false);

  // Convert File to Base64
  const processFile = (file: File) => {
    const reader = new FileReader();
    reader.onload = async () => {
      const base64String = reader.result as string;
      const base64Data = base64String.split(',')[1];
      const mimeType = file.type;

      setUploadedFile({
        file,
        previewUrl: base64String,
        base64: base64Data,
        mimeType
      });

      // Start Analysis immediately
      setState(AppState.ANALYZING);
      setError(null);

      try {
        const result = await analyzeDocument(base64Data, mimeType);
        setAnalysis(result);
        setState(AppState.VIEWING);
      } catch (err) {
        console.error(err);
        setError("Failed to analyze document. Please check your API key or try a different image.");
        setState(AppState.ERROR);
      }
    };
    reader.readAsDataURL(file);
  };

  const handleReset = () => {
    setState(AppState.IDLE);
    setUploadedFile(null);
    setAnalysis(null);
    setError(null);
  };

  return (
    <div className="flex flex-col h-screen bg-slate-50 text-slate-900 font-sans">
      {/* Header */}
      <header className="flex-none bg-white border-b border-slate-200 px-6 py-4 z-10 flex items-center justify-between shadow-sm">
        <div className="flex items-center gap-3">
          <div className="bg-indigo-600 p-2 rounded-lg">
             <Icons.Scan className="w-5 h-5 text-white" />
          </div>
          <h1 className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-indigo-600 to-violet-600">
            DocuLens
          </h1>
        </div>
        <div>
           {uploadedFile && (
             <button 
                onClick={handleReset}
                className="text-sm font-medium text-slate-500 hover:text-red-500 transition-colors flex items-center gap-1"
             >
               <Icons.Close className="w-4 h-4" />
               Reset
             </button>
           )}
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-1 overflow-hidden relative">
        {state === AppState.IDLE && (
          <div className="h-full flex flex-col items-center justify-center p-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
            <div className="max-w-md w-full space-y-8">
              <div className="text-center space-y-2">
                <h2 className="text-3xl font-bold text-slate-800">Analyze Documents Instantly</h2>
                <p className="text-slate-500">Upload any receipt, invoice, or note to extract insights, data, and chat with your content.</p>
              </div>
              <FileUploader onFileSelect={processFile} />

              <div className="pt-8 grid grid-cols-3 gap-4 text-center">
                 <div className="p-4 bg-white rounded-xl border border-slate-100 shadow-sm">
                    <Icons.File className="w-6 h-6 mx-auto mb-2 text-indigo-500" />
                    <span className="text-xs font-semibold text-slate-600">Extract Data</span>
                 </div>
                 <div className="p-4 bg-white rounded-xl border border-slate-100 shadow-sm">
                    <Icons.Scan className="w-6 h-6 mx-auto mb-2 text-violet-500" />
                    <span className="text-xs font-semibold text-slate-600">Summarize</span>
                 </div>
                 <div className="p-4 bg-white rounded-xl border border-slate-100 shadow-sm">
                    <Icons.Chat className="w-6 h-6 mx-auto mb-2 text-fuchsia-500" />
                    <span className="text-xs font-semibold text-slate-600">Q&A</span>
                 </div>
              </div>
            </div>
          </div>
        )}

        {state === AppState.ANALYZING && (
          <div className="h-full flex flex-col items-center justify-center p-6 animate-in fade-in duration-300">
             <div className="relative">
                <div className="absolute inset-0 bg-indigo-500 blur-xl opacity-20 rounded-full animate-pulse"></div>
                <div className="relative bg-white p-8 rounded-2xl shadow-xl border border-slate-100 text-center max-w-sm w-full">
                  <Icons.Spinner className="w-10 h-10 text-indigo-600 animate-spin mx-auto mb-4" />
                  <h3 className="text-lg font-semibold text-slate-800 mb-1">Analyzing Document</h3>
                  <p className="text-sm text-slate-500">Gemini Vision is processing your file...</p>
                </div>
             </div>
          </div>
        )}

        {state === AppState.ERROR && (
           <div className="h-full flex flex-col items-center justify-center p-6">
             <div className="bg-red-50 p-8 rounded-2xl border border-red-100 text-center max-w-sm">
               <Icons.Alert className="w-10 h-10 text-red-500 mx-auto mb-4" />
               <h3 className="text-lg font-semibold text-red-800 mb-2">Analysis Failed</h3>
               <p className="text-sm text-red-600 mb-6">{error}</p>
               <button 
                 onClick={handleReset}
                 className="bg-white border border-red-200 text-red-600 px-4 py-2 rounded-lg text-sm font-medium hover:bg-red-50 transition-colors"
               >
                 Try Again
               </button>
             </div>
           </div>
        )}

        {state === AppState.VIEWING && uploadedFile && analysis && (
          <div className="h-full flex flex-col lg:flex-row overflow-hidden">
            {/* Left Panel: Document Preview */}
            <div className={`
               lg:w-1/2 flex flex-col bg-slate-100 border-r border-slate-200 relative transition-all duration-300
               ${showFullImage ? 'fixed inset-0 z-50 w-full' : 'h-1/2 lg:h-full'}
            `}>
               <div className="absolute top-4 right-4 z-10 flex gap-2">
                 <button 
                   onClick={() => setShowFullImage(!showFullImage)}
                   className="p-2 bg-black/50 hover:bg-black/70 text-white rounded-lg backdrop-blur-sm transition-colors"
                   title={showFullImage ? "Minimize" : "Maximize"}
                 >
                   {showFullImage ? <Icons.Minimize className="w-5 h-5" /> : <Icons.Maximize className="w-5 h-5" />}
                 </button>
               </div>
               <div className="flex-1 overflow-auto flex items-center justify-center p-8">
                 <img 
